import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query"
import { get, post, put, del } from "@/lib/api"
import type { Exam, PageResult } from "@/types"

const ADMIN_EXAMS_KEY = "admin-exams"

/** 管理员获取试卷列表（分页） */
export function useAdminExamList(page: number, size: number) {
  return useQuery<PageResult<Exam>>({
    queryKey: [ADMIN_EXAMS_KEY, page, size],
    queryFn: () => get<PageResult<Exam>>(`/api/admin/exams?page=${page}&size=${size}`),
  })
}

/** 创建试卷 */
export function useCreateExam() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: (data: Partial<Exam>) => post<Exam>("/api/admin/exams", data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: [ADMIN_EXAMS_KEY] })
    },
  })
}

/** 更新试卷 */
export function useUpdateExam() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: ({ id, ...data }: Partial<Exam> & { id: number }) =>
      put<void>(`/api/admin/exams/${id}`, data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: [ADMIN_EXAMS_KEY] })
    },
  })
}

/** 删除试卷 */
export function useDeleteExam() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: (id: number) => del<void>(`/api/admin/exams/${id}`),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: [ADMIN_EXAMS_KEY] })
    },
  })
}

/** 发布试卷 */
export function usePublishExam() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: (id: number) => put<void>(`/api/admin/exams/${id}/publish`),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: [ADMIN_EXAMS_KEY] })
    },
  })
}

/** 关闭试卷 */
export function useCloseExam() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: (id: number) => put<void>(`/api/admin/exams/${id}/close`),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: [ADMIN_EXAMS_KEY] })
    },
  })
}

import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query"
import { get, post, put, del } from "@/lib/api"
import type { Question } from "@/types"

const QUESTIONS_KEY = "admin-questions"

/** 获取试卷题目列表 */
export function useQuestionList(examId: number) {
  return useQuery<Question[]>({
    queryKey: [QUESTIONS_KEY, examId],
    queryFn: () => get<Question[]>(`/api/admin/exams/${examId}/questions`),
    enabled: examId > 0,
  })
}

/** 添加单个题目 */
export function useAddQuestion() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: ({ examId, ...data }: Partial<Question> & { examId: number }) =>
      post<Question>(`/api/admin/exams/${examId}/questions`, data),
    onSuccess: (_data, variables) => {
      queryClient.invalidateQueries({ queryKey: [QUESTIONS_KEY, variables.examId] })
    },
  })
}

/** 批量导入题目 */
export function useBatchImport() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: ({ examId, questions }: { examId: number; questions: Partial<Question>[] }) =>
      post<void>(`/api/admin/exams/${examId}/questions/batch`, questions),
    onSuccess: (_data, variables) => {
      queryClient.invalidateQueries({ queryKey: [QUESTIONS_KEY, variables.examId] })
    },
  })
}

/** 更新题目 */
export function useUpdateQuestion() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: ({
      examId,
      id,
      ...data
    }: Partial<Question> & { examId: number; id: number }) =>
      put<void>(`/api/admin/exams/${examId}/questions/${id}`, data),
    onSuccess: (_data, variables) => {
      queryClient.invalidateQueries({ queryKey: [QUESTIONS_KEY, variables.examId] })
    },
  })
}

/** 删除题目 */
export function useDeleteQuestion() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: ({ examId, id }: { examId: number; id: number }) =>
      del<void>(`/api/admin/exams/${examId}/questions/${id}`),
    onSuccess: (_data, variables) => {
      queryClient.invalidateQueries({ queryKey: [QUESTIONS_KEY, variables.examId] })
    },
  })
}

