import { useState } from "react"
import { useTranslation } from "react-i18next"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Textarea } from "@/components/ui/textarea"
import { Label } from "@/components/ui/label"
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group"
import type { Question } from "@/types"

interface QuestionFormProps {
  defaultValues?: Partial<Question>
  onSubmit: (data: Partial<Question>) => void
  onCancel: () => void
}

const ANSWER_OPTIONS = ["A", "B", "C", "D"] as const

export function QuestionForm({ defaultValues, onSubmit, onCancel }: QuestionFormProps) {
  const { t } = useTranslation()
  const [content, setContent] = useState(defaultValues?.content ?? "")
  const [optionA, setOptionA] = useState(defaultValues?.optionA ?? "")
  const [optionB, setOptionB] = useState(defaultValues?.optionB ?? "")
  const [optionC, setOptionC] = useState(defaultValues?.optionC ?? "")
  const [optionD, setOptionD] = useState(defaultValues?.optionD ?? "")
  const [correctAnswer, setCorrectAnswer] = useState(defaultValues?.correctAnswer ?? "A")
  const [analysis, setAnalysis] = useState(defaultValues?.analysis ?? "")

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault()
    onSubmit({ content, optionA, optionB, optionC, optionD, correctAnswer, analysis: analysis || undefined })
  }

  const optionSetters = { A: setOptionA, B: setOptionB, C: setOptionC, D: setOptionD }
  const optionValues = { A: optionA, B: optionB, C: optionC, D: optionD }

  return (
    <form onSubmit={handleSubmit} className="space-y-4">
      {/* 题目内容 */}
      <div className="space-y-2">
        <Label>{t("admin.questionContent")}</Label>
        <Textarea
          value={content}
          onChange={(e) => setContent(e.target.value)}
          placeholder={t("admin.questionContentPlaceholder")}
          required
        />
      </div>

      {/* 选项 A-D */}
      {ANSWER_OPTIONS.map((opt) => (
        <div key={opt} className="space-y-2">
          <Label>{t("admin.option")} {opt}</Label>
          <Input
            value={optionValues[opt]}
            onChange={(e) => optionSetters[opt](e.target.value)}
            placeholder={`${t("admin.option")} ${opt}`}
            required
          />
        </div>
      ))}

      {/* 正确答案 */}
      <div className="space-y-2">
        <Label>{t("admin.correctAnswer")}</Label>
        <RadioGroup
          value={correctAnswer}
          onValueChange={setCorrectAnswer}
          className="flex gap-4"
        >
          {ANSWER_OPTIONS.map((opt) => (
            <div key={opt} className="flex items-center gap-2">
              <RadioGroupItem value={opt} id={`answer-${opt}`} />
              <Label htmlFor={`answer-${opt}`}>{opt}</Label>
            </div>
          ))}
        </RadioGroup>
      </div>

      {/* 解析（可选） */}
      <div className="space-y-2">
        <Label>{t("admin.analysis")} ({t("admin.optional")})</Label>
        <Textarea
          value={analysis}
          onChange={(e) => setAnalysis(e.target.value)}
          placeholder={t("admin.analysisPlaceholder")}
        />
      </div>

      {/* 按钮 */}
      <div className="flex justify-end gap-2 pt-2">
        <Button type="button" variant="outline" onClick={onCancel}>
          {t("common.cancel")}
        </Button>
        <Button type="submit">{t("common.save")}</Button>
      </div>
    </form>
  )
}

import { useState } from "react"
import { createFileRoute, useNavigate } from "@tanstack/react-router"
import { useTranslation } from "react-i18next"
import { toast } from "sonner"
import { Plus, Pencil, Trash2, Eye, Users, BarChart3, Send, XCircle } from "lucide-react"
import { Button } from "@/components/ui/button"
import { Badge } from "@/components/ui/badge"
import {
  Table,
  TableHeader,
  TableBody,
  TableRow,
  TableHead,
  TableCell,
} from "@/components/ui/table"
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
} from "@/components/ui/dialog"
import { useAdminExamList, useDeleteExam, usePublishExam, useCloseExam } from "@/hooks/use-admin-exams"
import type { Exam, ExamStatus } from "@/types"

export const Route = createFileRoute("/_layout/admin/exams/")({
  component: AdminExamListPage,
})

/** 状态 badge 变体映射 */
const STATUS_BADGE_VARIANT: Record<ExamStatus, "secondary" | "default" | "destructive"> = {
  draft: "secondary",
  published: "default",
  closed: "destructive",
}

const STATUS_LABEL: Record<ExamStatus, string> = {
  draft: "草稿",
  published: "已发布",
  closed: "已关闭",
}

function AdminExamListPage() {
  const { t } = useTranslation()
  const navigate = useNavigate()
  const [page, setPage] = useState(1)
  const pageSize = 10
  const { data, isLoading } = useAdminExamList(page, pageSize)

  const deleteMutation = useDeleteExam()
  const publishMutation = usePublishExam()
  const closeMutation = useCloseExam()

  const [deleteTarget, setDeleteTarget] = useState<Exam | null>(null)

  const handleDelete = () => {
    if (!deleteTarget) return
    deleteMutation.mutate(deleteTarget.id, {
      onSuccess: () => {
        toast.success(t("admin.deleteSuccess"))
        setDeleteTarget(null)
      },
      onError: (err) => toast.error(err.message),
    })
  }

  const handlePublish = (id: number) => {
    publishMutation.mutate(id, {
      onSuccess: () => toast.success(t("admin.publishSuccess")),
      onError: (err) => toast.error(err.message),
    })
  }

  const handleClose = (id: number) => {
    closeMutation.mutate(id, {
      onSuccess: () => toast.success(t("admin.closeSuccess")),
      onError: (err) => toast.error(err.message),
    })
  }

  const totalPages = data ? Math.ceil(data.total / pageSize) : 0

  return (
    <div className="space-y-4">
      {/* 头部 */}
      <div className="flex items-center justify-between">
        <h1 className="text-xl font-semibold">{t("nav.examManagement")}</h1>
        <Button onClick={() => navigate({ to: "/admin/exams/create" })}>
          <Plus className="h-4 w-4" />
          {t("admin.createExam")}
        </Button>
      </div>

      {/* 表格 */}
      {isLoading ? (
        <div className="py-10 text-center text-muted-foreground">{t("common.loading")}</div>
      ) : !data?.records.length ? (
        <div className="py-10 text-center text-muted-foreground">{t("common.noData")}</div>
      ) : (
        <>
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>{t("admin.examTitle")}</TableHead>
                <TableHead>{t("admin.status")}</TableHead>
                <TableHead>{t("admin.questionCount")}</TableHead>
                <TableHead>{t("admin.createdAt")}</TableHead>
                <TableHead className="text-right">{t("common.actions")}</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {data.records.map((exam) => (
                <TableRow key={exam.id}>
                  <TableCell className="font-medium">{exam.title}</TableCell>
                  <TableCell>
                    <Badge variant={STATUS_BADGE_VARIANT[exam.status]}>
                      {STATUS_LABEL[exam.status]}
                    </Badge>
                  </TableCell>
                  <TableCell>{exam.questionCount}</TableCell>
                  <TableCell>{new Date(exam.createdAt).toLocaleDateString()}</TableCell>
                  <TableCell>
                    <div className="flex justify-end gap-1">
                      {/* 草稿状态：编辑、发布、删除 */}
                      {exam.status === "draft" && (
                        <>
                          <Button
                            variant="ghost"
                            size="icon"
                            title={t("common.edit")}
                            onClick={() => navigate({ to: `/admin/exams/${exam.id}/edit` })}
                          >
                            <Pencil className="h-4 w-4" />
                          </Button>
                          <Button
                            variant="ghost"
                            size="icon"
                            title={t("admin.publish")}
                            onClick={() => handlePublish(exam.id)}
                          >
                            <Send className="h-4 w-4" />
                          </Button>
                          <Button
                            variant="ghost"
                            size="icon"
                            title={t("common.delete")}
                            onClick={() => setDeleteTarget(exam)}
                          >
                            <Trash2 className="h-4 w-4" />
                          </Button>
                        </>
                      )}
                      {/* 已发布状态：关闭 */}
                      {exam.status === "published" && (
                        <Button
                          variant="ghost"
                          size="icon"
                          title={t("admin.close")}
                          onClick={() => handleClose(exam.id)}
                        >
                          <XCircle className="h-4 w-4" />
                        </Button>
                      )}
                      {/* 所有状态：题目管理、白名单、分析 */}
                      <Button
                        variant="ghost"
                        size="icon"
                        title={t("admin.manageQuestions")}
                        onClick={() => navigate({ to: `/admin/exams/${exam.id}/questions` })}
                      >
                        <Eye className="h-4 w-4" />
                      </Button>
                      <Button
                        variant="ghost"
                        size="icon"
                        title={t("admin.whitelist")}
                        onClick={() => navigate({ to: `/admin/exams/${exam.id}/whitelist` })}
                      >
                        <Users className="h-4 w-4" />
                      </Button>
                      <Button
                        variant="ghost"
                        size="icon"
                        title={t("admin.analysisTab")}
                        onClick={() => navigate({ to: `/admin/exams/${exam.id}/analysis` })}
                      >
                        <BarChart3 className="h-4 w-4" />
                      </Button>
                    </div>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>

          {/* 分页 */}
          {totalPages > 1 && (
            <div className="flex items-center justify-end gap-2">
              <Button
                variant="outline"
                size="sm"
                disabled={page <= 1}
                onClick={() => setPage((p) => p - 1)}
              >
                {t("admin.prevPage")}
              </Button>
              <span className="text-sm text-muted-foreground">
                {page} / {totalPages}
              </span>
              <Button
                variant="outline"
                size="sm"
                disabled={page >= totalPages}
                onClick={() => setPage((p) => p + 1)}
              >
                {t("admin.nextPage")}
              </Button>
            </div>
          )}
        </>
      )}

      {/* 删除确认弹窗 */}
      <Dialog open={!!deleteTarget} onOpenChange={(open) => !open && setDeleteTarget(null)}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>{t("admin.confirmDelete")}</DialogTitle>
            <DialogDescription>
              {t("admin.confirmDeleteDesc", { title: deleteTarget?.title })}
            </DialogDescription>
          </DialogHeader>
          <DialogFooter>
            <Button variant="outline" onClick={() => setDeleteTarget(null)}>
              {t("common.cancel")}
            </Button>
            <Button variant="destructive" onClick={handleDelete} disabled={deleteMutation.isPending}>
              {t("common.delete")}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  )
}

import { useState } from "react"
import { createFileRoute, useNavigate } from "@tanstack/react-router"
import { useTranslation } from "react-i18next"
import { toast } from "sonner"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Switch } from "@/components/ui/switch"
import { Select, SelectTrigger, SelectContent, SelectItem, SelectValue } from "@/components/ui/select"
import { useCreateExam } from "@/hooks/use-admin-exams"
import type { AccessMode } from "@/types"

export const Route = createFileRoute("/_layout/admin/exams/create")({
  component: CreateExamPage,
})

function CreateExamPage() {
  const { t } = useTranslation()
  const navigate = useNavigate()
  const createMutation = useCreateExam()

  const [title, setTitle] = useState("")
  const [timeLimitMin, setTimeLimitMin] = useState(60)
  const [questionCount, setQuestionCount] = useState(0)
  const [showAnswer, setShowAnswer] = useState(false)
  const [showAnalysis, setShowAnalysis] = useState(false)
  const [maxAttempts, setMaxAttempts] = useState(1)
  const [accessMode, setAccessMode] = useState<AccessMode>("open")

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault()
    createMutation.mutate(
      { title, timeLimitMin, questionCount, showAnswer, showAnalysis, maxAttempts, accessMode },
      {
        onSuccess: () => {
          toast.success(t("admin.createSuccess"))
          navigate({ to: "/admin/exams" })
        },
        onError: (err) => toast.error(err.message),
      },
    )
  }

  return (
    <div className="mx-auto max-w-2xl space-y-6">
      <div className="flex items-center justify-between">
        <h1 className="text-xl font-semibold">{t("admin.createExam")}</h1>
        <Button variant="outline" onClick={() => navigate({ to: "/admin/exams" })}>
          {t("common.back")}
        </Button>
      </div>

      <form onSubmit={handleSubmit} className="space-y-4">
        {/* 标题 */}
        <div className="space-y-2">
          <Label>{t("admin.examTitle")}</Label>
          <Input value={title} onChange={(e) => setTitle(e.target.value)} required />
        </div>

        {/* 时间限制 */}
        <div className="space-y-2">
          <Label>{t("admin.timeLimit")}</Label>
          <Input
            type="number"
            min={1}
            value={timeLimitMin}
            onChange={(e) => setTimeLimitMin(Number(e.target.value))}
            required
          />
        </div>

        {/* 题目数量 */}
        <div className="space-y-2">
          <Label>{t("admin.questionCount")}</Label>
          <Input
            type="number"
            min={0}
            value={questionCount}
            onChange={(e) => setQuestionCount(Number(e.target.value))}
            required
          />
        </div>

        {/* 最大尝试次数 */}
        <div className="space-y-2">
          <Label>{t("admin.maxAttempts")}</Label>
          <Input
            type="number"
            min={1}
            value={maxAttempts}
            onChange={(e) => setMaxAttempts(Number(e.target.value))}
            required
          />
        </div>

        {/* 访问模式 */}
        <div className="space-y-2">
          <Label>{t("admin.accessMode")}</Label>
          <Select value={accessMode} onValueChange={(v) => setAccessMode(v as AccessMode)}>
            <SelectTrigger>
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="open">{t("admin.accessOpen")}</SelectItem>
              <SelectItem value="whitelist">{t("admin.accessWhitelist")}</SelectItem>
            </SelectContent>
          </Select>
        </div>

        {/* 开关选项 */}
        <div className="flex items-center justify-between rounded-md border p-3">
          <Label>{t("admin.showAnswer")}</Label>
          <Switch checked={showAnswer} onCheckedChange={setShowAnswer} />
        </div>

        <div className="flex items-center justify-between rounded-md border p-3">
          <Label>{t("admin.showAnalysis")}</Label>
          <Switch checked={showAnalysis} onCheckedChange={setShowAnalysis} />
        </div>

        {/* 提交 */}
        <div className="flex justify-end gap-2 pt-4">
          <Button
            type="button"
            variant="outline"
            onClick={() => navigate({ to: "/admin/exams" })}
          >
            {t("common.cancel")}
          </Button>
          <Button type="submit" disabled={createMutation.isPending}>
            {t("common.create")}
          </Button>
        </div>
      </form>
    </div>
  )
}

import { useState, useEffect } from "react"
import { createFileRoute, useNavigate, useParams } from "@tanstack/react-router"
import { useQuery } from "@tanstack/react-query"
import { useTranslation } from "react-i18next"
import { toast } from "sonner"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Switch } from "@/components/ui/switch"
import { Select, SelectTrigger, SelectContent, SelectItem, SelectValue } from "@/components/ui/select"
import { useUpdateExam } from "@/hooks/use-admin-exams"
import { get } from "@/lib/api"
import type { Exam, AccessMode } from "@/types"

export const Route = createFileRoute("/_layout/admin/exams/$id/edit")({
  component: EditExamPage,
})

function EditExamPage() {
  const { t } = useTranslation()
  const navigate = useNavigate()
  const { id } = useParams({ from: "/_layout/admin/exams/$id/edit" })
  const examId = Number(id)
  const updateMutation = useUpdateExam()

  // 获取试卷详情（复用考生端接口）
  const { data: exam, isLoading } = useQuery<Exam>({
    queryKey: ["exam-detail", examId],
    queryFn: () => get<Exam>(`/api/exams/${examId}`),
    enabled: examId > 0,
  })

  const [title, setTitle] = useState("")
  const [timeLimitMin, setTimeLimitMin] = useState(60)
  const [questionCount, setQuestionCount] = useState(0)
  const [showAnswer, setShowAnswer] = useState(false)
  const [showAnalysis, setShowAnalysis] = useState(false)
  const [maxAttempts, setMaxAttempts] = useState(1)
  const [accessMode, setAccessMode] = useState<AccessMode>("open")

  // 数据加载后填充表单
  useEffect(() => {
    if (!exam) return
    setTitle(exam.title)
    setTimeLimitMin(exam.timeLimitMin)
    setQuestionCount(exam.questionCount)
    setShowAnswer(exam.showAnswer)
    setShowAnalysis(exam.showAnalysis)
    setMaxAttempts(exam.maxAttempts)
    setAccessMode(exam.accessMode)
  }, [exam])

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault()
    updateMutation.mutate(
      { id: examId, title, timeLimitMin, questionCount, showAnswer, showAnalysis, maxAttempts, accessMode },
      {
        onSuccess: () => {
          toast.success(t("admin.updateSuccess"))
          navigate({ to: "/admin/exams" })
        },
        onError: (err) => toast.error(err.message),
      },
    )
  }

  if (isLoading) {
    return <div className="py-10 text-center text-muted-foreground">{t("common.loading")}</div>
  }

  return (
    <div className="mx-auto max-w-2xl space-y-6">
      <div className="flex items-center justify-between">
        <h1 className="text-xl font-semibold">{t("admin.editExam")}</h1>
        <Button variant="outline" onClick={() => navigate({ to: "/admin/exams" })}>
          {t("common.back")}
        </Button>
      </div>

      <form onSubmit={handleSubmit} className="space-y-4">
        <div className="space-y-2">
          <Label>{t("admin.examTitle")}</Label>
          <Input value={title} onChange={(e) => setTitle(e.target.value)} required />
        </div>

        <div className="space-y-2">
          <Label>{t("admin.timeLimit")}</Label>
          <Input
            type="number"
            min={1}
            value={timeLimitMin}
            onChange={(e) => setTimeLimitMin(Number(e.target.value))}
            required
          />
        </div>

        <div className="space-y-2">
          <Label>{t("admin.questionCount")}</Label>
          <Input
            type="number"
            min={0}
            value={questionCount}
            onChange={(e) => setQuestionCount(Number(e.target.value))}
            required
          />
        </div>

        <div className="space-y-2">
          <Label>{t("admin.maxAttempts")}</Label>
          <Input
            type="number"
            min={1}
            value={maxAttempts}
            onChange={(e) => setMaxAttempts(Number(e.target.value))}
            required
          />
        </div>

        <div className="space-y-2">
          <Label>{t("admin.accessMode")}</Label>
          <Select value={accessMode} onValueChange={(v) => setAccessMode(v as AccessMode)}>
            <SelectTrigger>
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="open">{t("admin.accessOpen")}</SelectItem>
              <SelectItem value="whitelist">{t("admin.accessWhitelist")}</SelectItem>
            </SelectContent>
          </Select>
        </div>

        <div className="flex items-center justify-between rounded-md border p-3">
          <Label>{t("admin.showAnswer")}</Label>
          <Switch checked={showAnswer} onCheckedChange={setShowAnswer} />
        </div>

        <div className="flex items-center justify-between rounded-md border p-3">
          <Label>{t("admin.showAnalysis")}</Label>
          <Switch checked={showAnalysis} onCheckedChange={setShowAnalysis} />
        </div>

        <div className="flex justify-end gap-2 pt-4">
          <Button
            type="button"
            variant="outline"
            onClick={() => navigate({ to: "/admin/exams" })}
          >
            {t("common.cancel")}
          </Button>
          <Button type="submit" disabled={updateMutation.isPending}>
            {t("common.save")}
          </Button>
        </div>
      </form>
    </div>
  )
}

import { useState } from "react"
import { createFileRoute, useParams } from "@tanstack/react-router"
import { useTranslation } from "react-i18next"
import { toast } from "sonner"
import { Plus, Pencil, Trash2 } from "lucide-react"
import { Button } from "@/components/ui/button"
import {
  Table,
  TableHeader,
  TableBody,
  TableRow,
  TableHead,
  TableCell,
} from "@/components/ui/table"
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
} from "@/components/ui/dialog"
import { QuestionForm } from "@/components/question-form"
import {
  useQuestionList,
  useAddQuestion,
  useUpdateQuestion,
  useDeleteQuestion,
} from "@/hooks/use-admin-questions"
import type { Question } from "@/types"

export const Route = createFileRoute("/_layout/admin/exams/$id/questions")({
  component: ManageQuestionsPage,
})

function ManageQuestionsPage() {
  const { t } = useTranslation()
  const { id } = useParams({ from: "/_layout/admin/exams/$id/questions" })
  const examId = Number(id)

  const { data: questions, isLoading } = useQuestionList(examId)
  const addMutation = useAddQuestion()
  const updateMutation = useUpdateQuestion()
  const deleteMutation = useDeleteQuestion()

  const [showAddDialog, setShowAddDialog] = useState(false)
  const [editingQuestion, setEditingQuestion] = useState<Question | null>(null)
  const [deleteTarget, setDeleteTarget] = useState<Question | null>(null)

  const handleAdd = (data: Partial<Question>) => {
    addMutation.mutate(
      { examId, ...data },
      {
        onSuccess: () => {
          toast.success(t("admin.addQuestionSuccess"))
          setShowAddDialog(false)
        },
        onError: (err) => toast.error(err.message),
      },
    )
  }

  const handleUpdate = (data: Partial<Question>) => {
    if (!editingQuestion) return
    updateMutation.mutate(
      { examId, id: editingQuestion.id, ...data },
      {
        onSuccess: () => {
          toast.success(t("admin.updateSuccess"))
          setEditingQuestion(null)
        },
        onError: (err) => toast.error(err.message),
      },
    )
  }

  const handleDelete = () => {
    if (!deleteTarget) return
    deleteMutation.mutate(
      { examId, id: deleteTarget.id },
      {
        onSuccess: () => {
          toast.success(t("admin.deleteSuccess"))
          setDeleteTarget(null)
        },
        onError: (err) => toast.error(err.message),
      },
    )
  }

  /** 截断文本显示 */
  const truncate = (text: string, maxLen = 50) =>
    text.length > maxLen ? `${text.slice(0, maxLen)}...` : text

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <h1 className="text-xl font-semibold">{t("admin.manageQuestions")}</h1>
        <Button onClick={() => setShowAddDialog(true)}>
          <Plus className="h-4 w-4" />
          {t("admin.addQuestion")}
        </Button>
      </div>

      {isLoading ? (
        <div className="py-10 text-center text-muted-foreground">{t("common.loading")}</div>
      ) : !questions?.length ? (
        <div className="py-10 text-center text-muted-foreground">{t("common.noData")}</div>
      ) : (
        <Table>
          <TableHeader>
            <TableRow>
              <TableHead className="w-16">#</TableHead>
              <TableHead>{t("admin.questionContent")}</TableHead>
              <TableHead className="w-24">{t("admin.correctAnswer")}</TableHead>
              <TableHead className="w-24 text-right">{t("common.actions")}</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {questions.map((q) => (
              <TableRow key={q.id}>
                <TableCell>{q.sortOrder}</TableCell>
                <TableCell>{truncate(q.content)}</TableCell>
                <TableCell>{q.correctAnswer}</TableCell>
                <TableCell>
                  <div className="flex justify-end gap-1">
                    <Button
                      variant="ghost"
                      size="icon"
                      title={t("common.edit")}
                      onClick={() => setEditingQuestion(q)}
                    >
                      <Pencil className="h-4 w-4" />
                    </Button>
                    <Button
                      variant="ghost"
                      size="icon"
                      title={t("common.delete")}
                      onClick={() => setDeleteTarget(q)}
                    >
                      <Trash2 className="h-4 w-4" />
                    </Button>
                  </div>
                </TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
      )}

      {/* 新增题目弹窗 */}
      <Dialog open={showAddDialog} onOpenChange={setShowAddDialog}>
        <DialogContent className="max-w-2xl">
          <DialogHeader>
            <DialogTitle>{t("admin.addQuestion")}</DialogTitle>
          </DialogHeader>
          <QuestionForm onSubmit={handleAdd} onCancel={() => setShowAddDialog(false)} />
        </DialogContent>
      </Dialog>

      {/* 编辑题目弹窗 */}
      <Dialog open={!!editingQuestion} onOpenChange={(open) => !open && setEditingQuestion(null)}>
        <DialogContent className="max-w-2xl">
          <DialogHeader>
            <DialogTitle>{t("admin.editQuestion")}</DialogTitle>
          </DialogHeader>
          {editingQuestion && (
            <QuestionForm
              defaultValues={editingQuestion}
              onSubmit={handleUpdate}
              onCancel={() => setEditingQuestion(null)}
            />
          )}
        </DialogContent>
      </Dialog>

      {/* 删除确认弹窗 */}
      <Dialog open={!!deleteTarget} onOpenChange={(open) => !open && setDeleteTarget(null)}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>{t("admin.confirmDelete")}</DialogTitle>
            <DialogDescription>{t("admin.confirmDeleteQuestionDesc")}</DialogDescription>
          </DialogHeader>
          <DialogFooter>
            <Button variant="outline" onClick={() => setDeleteTarget(null)}>
              {t("common.cancel")}
            </Button>
            <Button variant="destructive" onClick={handleDelete} disabled={deleteMutation.isPending}>
              {t("common.delete")}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  )
}

